PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?team WHERE {
  ?player wdt:P31 wd:Q5727536;
          wdt:P106 wd:Q20923097;
          wdt:P535 "2008";
          wdt:P534 ?team.
}

